ALGORITHM CFG_to_PDA(G = (V, T, P, S))
BEGIN
 // Create PDA with single state q
 Q = {q}
 Σ = T (input alphabet)
 Γ = V ∪ T (stack alphabet)
 q₀ = q (initial state)
 Z = S (initial stack symbol)

 // Transition function δ
 FOR EACH production A → α IN P DO
 // Replace non-terminal A with its production α
 δ(q, ε, A) = {(q, reverse(α))}
 END FOR

 FOR EACH terminal a IN T DO
 // Match and consume terminal from input and stack
 δ(q, a, a) = {(q, ε)}
 END FOR

 // Accept by empty stack
 // PDA accepts when stack becomes empty
 RETURN PDA
END

